import React from "react";
import { Card } from "react-bootstrap";

export const EducationTile = ({education}) => {
  return (
    <Card>
      <Card.Header>
        {education.completionDate}
      </Card.Header>
      <Card.Body>
        {education.special ? <h6>{education.programName}</h6> : <h4 style={{fontWeight: "bold"}}>{education.programName}</h4>}
        {education.special && <h4 style={{fontWeight: "bold"}}>{education.special}</h4>}
        <span className={"text-muted"}>
          {education.institutionName} - {education.location}
        </span>
      </Card.Body>
    </Card>
  );
};
